class Solution:
    def totalHammingDistance(self, nums):
        # Brute force over all pairs, counting differing bits directly
        total = 0
        n = len(nums)
        for i in range(n):
            for j in range(i + 1, n):
                total += bin(nums[i] ^ nums[j]).count('1')
        return total

