var totalHammingDistance = function(nums) {
    const n = nums.length;
    let total = 0;
    for (let bit = 0; bit < 31; bit++) {
        let ones = 0;
        for (const v of nums) ones += Math.floor(v / Math.pow(2, bit)) % 2;
        total += ones * (n - ones);
    }
    return total;
};
